var e=JSON.parse(`[{"id":"L3_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"휴우.","JPN":"ふう……","ENG":"Phew...","TWN":"呼。"},"stage":{"bg":"COUNTERSIDE_NORMAL","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L4_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"남은 침식코어는 이게 마지막이었던 것 같아.","JPN":"残りの侵食コアはこれが最後みたい。","ENG":"I believe that was the last remaining Corruption Core.","TWN":"這應該是最後一個侵蝕核心吧？"},"stage":{"bg":"COUNTERSIDE_NORMAL","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"음?","JPN":"あれ？","ENG":"Mm?","TWN":"嗯？"},"stage":{"bg":"COUNTERSIDE_NORMAL","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"선배, 그새 거기서 뭐하는 거야?","JPN":"先輩、そこで何してるの？","ENG":"Shiyoon, what are you doing over there?","TWN":"前輩，你在那裡幹嘛？"},"stage":{"bg":"COUNTERSIDE_NORMAL","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JOOSHIYOON_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_NULL_NULL","text":{"KOREA":"아, 미나 양. 여기서 재미있어 보이는 물건을 발견해서요.","JPN":"お、ミナさん。ここで面白そうな物を発見したんです。","ENG":"Oh, Mina. I've discovered an interesting-looking object here.","TWN":"喔，米娜，我發現一個感覺很好玩的東西。"},"stage":{"bg":"COUNTERSIDE_NORMAL","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JOOSHIYOON_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"물건?","JPN":"面白そうな物？","ENG":"What object?","TWN":"好玩的東西？"},"stage":{"bg":"COUNTERSIDE_NORMAL","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"뭐야. TV잖아? 이런 게 왜 여기 있는 거지?","JPN":"なんだ、テレビじゃない。なんでこんな所にあるんだろう？","ENG":"What the...? It's a TV. What is it doing here?","TWN":"嗟，不就是電視嗎！不過它怎麼會在這裡？"},"stage":{"bg":"COUNTERSIDE_NORMAL","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JOOSHIYOON_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L13_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_NULL_NULL","text":{"KOREA":"글쎄요. 아마도 누가 함선에 싣고 왔다가 실수로 떨어트린 게 아닐까요?","JPN":"さあ。誰かが艦船に積んでいたものを落としたんじゃないでしょうか？","ENG":"Beats me. Maybe someone carried it here in their ship and accidentally dropped it.","TWN":"我也不清楚，可能是有人把它放在艦船裡，結果不小心掉出來吧？"},"stage":{"bg":"COUNTERSIDE_NORMAL","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JOOSHIYOON_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L15_1","type":"dialog","speaker":"TV_NPC_NOMA_NONAME","text":{"KOREA":"<color=#ffd34c>안녕하신가요, 여러분!</color>","JPN":"<color=#ffd34c>お初にお目にかかります、皆様！</color>","ENG":"<color=#ffd34c>Hello, everyone!</color>","TWN":"<color=#ffd34c>哈囉～你們好！</color>"},"stage":{"bg":"COUNTERSIDE_NORMAL","bgm":"THEMA_BOSS_PAWN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JOOSHIYOON_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"}}},"sfx":"FX_CUTSCEN_NOISE"},{"id":"L16_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"힉, 깜짝이야!","JPN":"うわっ、ビックリした！","ENG":"Heek! Geez!","TWN":"唔！嚇我一跳！"},"stage":{"bg":"COUNTERSIDE_NORMAL","bgm":"THEMA_BOSS_PAWN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JOOSHIYOON_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_HATE"}}}},{"id":"L17_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"TV가 켜진 건가?","JPN":"か、勝手に電源がついた！？","ENG":"Did it turn on by itself?","TWN":"電視機自己打開的嗎？"},"stage":{"bg":"COUNTERSIDE_NORMAL","bgm":"THEMA_BOSS_PAWN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JOOSHIYOON_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L19_1","type":"dialog","speaker":"TV_NPC_NOMA_NONAME","text":{"KOREA":"<color=#ffd34c>여러분은 좀비 퇴치를 좋아하시나요?</color>","JPN":"<color=#ffd34c>皆様はゾンビ退治はお好きでしょうか？</color>","ENG":"<color=#ffd34c>Do you like fighting zombies?</color>","TWN":"<color=#ffd34c>你們喜歡殺活屍媽？</color>"},"stage":{"bg":"COUNTERSIDE_NORMAL","bgm":"THEMA_BOSS_PAWN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JOOSHIYOON_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L20_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_NULL_NULL","text":{"KOREA":"흐음, 진짜 좀비를 본 적은 없지만 좀비를 잡는 게임이라면 몇 번 해봤는데요.","JPN":"うーん、本物のゾンビを見たことがありませんが、ゾンビを倒すゲームなら何回かプレイしたことがあります。","ENG":"Well, I've never seen zombies in real life, but I played a few zombie-hunting games.","TWN":"呵呵，我是沒見過真正的活屍啦～活屍遊戲倒是玩過幾次。"},"stage":{"bg":"COUNTERSIDE_NORMAL","bgm":"THEMA_BOSS_PAWN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JOOSHIYOON_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L21_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_NULL_NULL","text":{"KOREA":"미나 양은 어떠세요?","JPN":"ミナさんは？","ENG":"What about you, Mina?","TWN":"米娜呢？"},"stage":{"bg":"COUNTERSIDE_NORMAL","bgm":"THEMA_BOSS_PAWN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JOOSHIYOON_FENRIR_NULL_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L22_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"으응? 난 딱히 그런 게임 같은 건 해본 적 없는데. 좀비도 영화로만 봤고.","JPN":"え？　私はそんなゲームはやったことないよ。ゾンビだって映画でしか見たことない。","ENG":"Huh? I don't really play games. I've only seen zombies in movies, too.","TWN":"我喔？我沒玩過活屍遊戲，我只看過活屍電影。"},"stage":{"bg":"COUNTERSIDE_NORMAL","bgm":"THEMA_BOSS_PAWN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JOOSHIYOON_FENRIR_NULL_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L26_1","type":"dialog","speaker":"TV_NPC_NOMA_NONAME","text":{"KOREA":"<color=#ffd34c>그렇다면 두 분에겐 좋은 기회가 되겠군요! 오늘 좀비들을 마음껏 해치울 수 있을 테니까요!</color>","JPN":"<color=#ffd34c>ならばお二人にはちょうどいい機会になるでしょう！　本日はゾンビを好きなだけ退治できますから！</color>","ENG":"<color=#ffd34c>Then, this will be a great opportunity for both of you! Today, you can fight zombies all day long!</color>","TWN":"<color=#ffd34c>那這對兩位是千載難逢的好機會呢！今天可以盡情地殺活屍喔！</color>"},"stage":{"bg":"RELIC_OPERATION_02","bgm":"THEMA_BOSS_PAWN","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L27_1","type":"dialog","speaker":"TV_NPC_NOMA_NONAME","text":{"KOREA":"<color=#ffd34c>새로운 타이틀! 버려진 세계의 패잔병과 패자부활전 한바탕! 에 오신 것을 환영합니다!</color>","JPN":"<color=#ffd34c>新番組！　「捨てられた世界の敗残兵と敗者復活戦！」 へようこそ！</color>","ENG":"<color=#ffd34c>Let me introduce you to our brand-new title, \\"A Consolation Match with the Losers of the Abandoned World!\\"</color>","TWN":"<color=#ffd34c>全新主題！和失落世界的殘兵敗將來一場敗部復活戰！歡迎來挑戰！</color>"},"stage":{"bg":"RELIC_OPERATION_02","bgm":"THEMA_BOSS_PAWN","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}},"sfx":"FX_CUTSCEN_NOISE"},{"id":"L31_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"어라? 잠깐만. 방금 저 방송에서 우리가 하는 말에 대답한 거야?","JPN":"あれ？　待って、今あのテレビが私たちに話しかけているの？","ENG":"Err, wait just a second. Did he just answer us?","TWN":"真假？現在電視裡的節目是在和我們對話嗎？"},"stage":{"bg":"COUNTERSIDE_NORMAL","bgm":"THEMA_BOSS_PAWN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JOOSHIYOON_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_HATE"}}}},{"id":"L32_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_NULL_NULL","text":{"KOREA":"흐음, 더 신기한 건 이런 이면세계에서도 TV가 멀쩡하게 송출되고 있다는 거죠.","JPN":"ふむ、もっと不思議なのは、この裏世界でもあのテレビが普通に映っていることです。","ENG":"Hm, what's more interesting is that this TV is broadcasting in the middle of the Counterside.","TWN":"嗯嗯，更神奇的是，電視節目竟然可以在異界順利播放？！"},"stage":{"bg":"COUNTERSIDE_NORMAL","bgm":"THEMA_BOSS_PAWN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JOOSHIYOON_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_HATE"}}}},{"id":"L33_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"그, 그러게. 녹화된 미디어파일 같은 건가?","JPN":"た、確かに。録画されたメディアファイルとかかな？","ENG":"You're right. Could it be playing a recorded media file?","TWN":"對啊，是預錄的節目嗎？"},"stage":{"bg":"COUNTERSIDE_NORMAL","bgm":"THEMA_BOSS_PAWN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JOOSHIYOON_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L35_1","type":"dialog","speaker":"TV_NPC_NOMA_NONAME","text":{"KOREA":"<color=#ffd34c>천만에요! 제 쇼는 절대로 녹화나 재방송 따윌 허용하지 않는답니다!</color>","JPN":"<color=#ffd34c>とんでもない！　私のショーに録画放送や再放送なんて許されません！</color>","ENG":"<color=#ffd34c>Absolutely not! My show is never recorded or rerun!</color>","TWN":"<color=#ffd34c>話可別這麼說！我的節目可是從來不預錄或是重播的！</color>"},"stage":{"bg":"COUNTERSIDE_NORMAL","bgm":"THEMA_BOSS_PAWN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JOOSHIYOON_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L36_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"…뭐야. 누가 숨어서 장난치는 건가?","JPN":"……なんだ。誰か隠れてイタズラでもしているの？","ENG":"What the...? Is someone hiding here and playing tricks on us?","TWN":"…什麼鬼！是不是有人躲在裡面想整我們！"},"stage":{"bg":"COUNTERSIDE_NORMAL","bgm":"THEMA_BOSS_PAWN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JOOSHIYOON_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L38_1","type":"dialog","speaker":"TV_NPC_NOMA_NONAME","text":{"KOREA":"<color=#ffd34c>아! 말씀드리는 순간, 뒤편에서 상대측 선수들이 입장하는군요!</color>","JPN":"<color=#ffd34c>お！　ちょうど後ろから相手の選手たちが入場しました！</color>","ENG":"<color=#ffd34c>Oh! As if on cue, the opposing players have shown up from behind!</color>","TWN":"<color=#ffd34c>喔！就在我說明的時刻，選手們已經從後方進場囉！</color>"},"stage":{"bg":"COUNTERSIDE_NORMAL","bgm":"THEMA_BOSS_PAWN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JOOSHIYOON_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L40_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"뒤쪽이라고?","JPN":"後ろ？","ENG":"From behind where?","TWN":"後方？"},"stage":{"bg":"COUNTERSIDE_NORMAL","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L41_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"…….","TWN":"……"},"stage":{"bg":"COUNTERSIDE_NORMAL","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_CUTSCEN_FOOTSTEP_WALK_02"},{"id":"L43_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"선배. 지금 내가 보고 있는 거, 선배한테도 보이는 거지?","JPN":"先輩。今私が見ているものって先輩にも見えてるよね？","ENG":"Shiyoon. Are you seeing what I'm seeing?","TWN":"前輩，你有看到我看到的嗎？"},"stage":{"bg":"COUNTERSIDE_NORMAL","bgm":"THEMA_DIVE_BOTTOM","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L44_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_NULL_NULL","text":{"KOREA":"네, 소리도 없이 나타나서 하마터면 뒤를 잡힐 뻔했어요.","JPN":"はい、何の気配もなく現れて危ないところでしたね。","ENG":"Yes. They were so quiet that I almost didn't notice them.","TWN":"有，一聲不吭就冒出來，我差點沒注意到！"},"stage":{"bg":"COUNTERSIDE_NORMAL","bgm":"THEMA_DIVE_BOTTOM","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JOOSHIYOON_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L45_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_NULL_NULL","text":{"KOREA":"눈빛이 당장이라도 저희를 좀비처럼 물어뜯을 기세인데요?","JPN":"まるでゾンビのような、すぐにでも僕たちに噛み付きそうな目つきをしていますね。","ENG":"They've got hungry murder in their eyes, like zombies.","TWN":"你看他們的眼神，一副就是活屍要衝上來咬我們的樣子。"},"stage":{"bg":"COUNTERSIDE_NORMAL","bgm":"THEMA_DIVE_BOTTOM","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JOOSHIYOON_FENRIR_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L46_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"지원을 요청하는 게 좋을까?","JPN":"応援を呼んだほうがいいのかな？","ENG":"Should we call for reinforcements?","TWN":"需要請求支援嗎？"},"stage":{"bg":"COUNTERSIDE_NORMAL","bgm":"THEMA_DIVE_BOTTOM","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L48_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_NULL_NULL","text":{"KOREA":"어라?","JPN":"おや？","ENG":"Err?","TWN":"嗯？"},"stage":{"bg":"COUNTERSIDE_NORMAL","bgm":"THEMA_DIVE_BOTTOM","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JOOSHIYOON_FENRIR_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L49_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_NULL_NULL","text":{"KOREA":"에디 소대와 알트 소대로부터 지원 요청이 들어왔어요.","JPN":"エディー小隊とアルト小隊から応援要請が来ています。","ENG":"We've got reinforcement requests from the Eddie and ALT squads.","TWN":"艾迪小隊和阿爾特小隊也在請求支援。"},"stage":{"bg":"COUNTERSIDE_NORMAL","bgm":"THEMA_DIVE_BOTTOM","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JOOSHIYOON_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L50_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_NULL_NULL","text":{"KOREA":"아무래도, 문제가 생긴 건 저희 뿐만이 아닌 것 같네요.","JPN":"どうやら、トラブルが発生したのは僕たちだけではないようです。","ENG":"It seems we're not the only ones in trouble.","TWN":"看來有問題的不只是我們這裡。"},"stage":{"bg":"COUNTERSIDE_NORMAL","bgm":"THEMA_DIVE_BOTTOM","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JOOSHIYOON_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L3_1","type":"dialog","speaker":"TV_NPC_NOMA_NONAME","text":{"KOREA":"<color=#ffd34c>자, 선수들이 한 자리에 모였습니다!</color>","JPN":"<color=#ffd34c>さあ、選手が一堂に揃いましたね。</color>","ENG":"<color=#ffd34c>Alright, all the players have gathered in one place.</color>","TWN":"<color=#ffd34c>好的，現在選手們已經聚集在一處！</color>"},"stage":{"bg":"RELIC_OPERATION_02","bgm":"THEMA_DIVE_BOTTOM","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}},"sfx":"FX_CUTSCEN_NOISE"},{"id":"L4_1","type":"dialog","speaker":"TV_NPC_NOMA_NONAME","text":{"KOREA":"<color=#ffd34c>상대는 죽어버린 세계에서 희망의 냄새를 맡고 나타난 패배의 잔재! 그림자! 도플갱어!</color>","JPN":"<color=#ffd34c>相手は滅びた世界から希望の香りに惹かれて現れた敗北の残滓！　シャドウ！　ドッペルゲンガー！</color>","ENG":"<color=#ffd34c>Your opponents are the defeated remnants of a dead world that have smelled hope. Shadows! Doppelgangers!</color>","TWN":"<color=#ffd34c>對手是聞到希望的味道，而從死亡的泥沼中爬出來的喪家犬！暗影！二重身！</color>"},"stage":{"bg":"RELIC_OPERATION_02","bgm":"THEMA_DIVE_BOTTOM","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L5_1","type":"dialog","speaker":"TV_NPC_NOMA_NONAME","text":{"KOREA":"<color=#ffd34c>이야! 이 선수들, 별명이 너무 많아서 뭐라고 불러야 할 지도 모르겠군요!</color>","JPN":"<color=#ffd34c>やれやれ。この選手たち、名前が多すぎてなんて呼べばいいか迷っちゃいますね！</color>","ENG":"<color=#ffd34c>Wow, these guys have got so many nicknames, I don't know what to call them.</color>","TWN":"<color=#ffd34c>哇～選手的外號多到我都不知道該怎麼稱呼才好！</color>"},"stage":{"bg":"RELIC_OPERATION_02","bgm":"THEMA_DIVE_BOTTOM","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L10_1","type":"dialog","speaker":"TV_NPC_NOMA_NONAME","text":{"KOREA":"<color=#ffd34c>하지만 확실한 건, 저 패배자들을 오늘 두 카운터 선수가 쓰러트리게 될 것이라는 거죠!</color>","JPN":"<color=#ffd34c>しかし確実に言えることは、あの敗北者たちは本日、二人のカウンター選手によって倒されるということ！</color>","ENG":"<color=#ffd34c>What I do know is that they will be defeated by our two brave Counters here!</color>","TWN":"<color=#ffd34c>不過有一件事我可以確定！就是今天兩位制裁者選手會打倒那些喪家犬！</color>"},"stage":{"bg":"COUNTERSIDE_NORMAL","bgm":"THEMA_DIVE_BOTTOM","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JOOSHIYOON_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L11_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_NULL_NULL","text":{"KOREA":"어째 다 저희가 알고 있는 얼굴들이군요.","JPN":"どうやら僕たちが知っている顔のようですね。","ENG":"For some reason, they all look familiar to me.","TWN":"怎麼都是些熟面孔？"},"stage":{"bg":"COUNTERSIDE_NORMAL","bgm":"THEMA_DIVE_BOTTOM","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JOOSHIYOON_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L12_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"저 사람들이… 그림자라고? 대체 어떻게 된 거지?","JPN":"あの人たちが……シャドウに？　どうなってるの？","ENG":"They're... Shadows? What happened?","TWN":"那些人…是暗影？這是怎麼回事？"},"stage":{"bg":"COUNTERSIDE_NORMAL","bgm":"THEMA_DIVE_BOTTOM","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JOOSHIYOON_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L13_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_NULL_NULL","text":{"KOREA":"TV의 목소리가 저 사람들을 도플갱어라고 불렀어요.","JPN":"テレビの声はあれをドッペルゲンガーと呼んでいました。","ENG":"The voice from the TV called them Doppelgangers.","TWN":"電視裡的聲音說他們是二重身。"},"stage":{"bg":"COUNTERSIDE_NORMAL","bgm":"THEMA_DIVE_BOTTOM","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JOOSHIYOON_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L14_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"도플갱어?","JPN":"ドッペルゲンガー？","ENG":"Doppelgangers?","TWN":"二重身？"},"stage":{"bg":"COUNTERSIDE_NORMAL","bgm":"THEMA_DIVE_BOTTOM","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JOOSHIYOON_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L15_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_NULL_NULL","text":{"KOREA":"도플갱어 신드롬.","JPN":"ドッペルゲンガーシンドローム。","ENG":"Doppelganger syndrome.","TWN":"二重身症候群。"},"stage":{"bg":"COUNTERSIDE_NORMAL","bgm":"THEMA_DIVE_BOTTOM","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JOOSHIYOON_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L16_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_NULL_NULL","text":{"KOREA":"리플레이서 사태 이후로 출몰하기 시작한 반쪽짜리 그림자입니다.","JPN":"リプレイサー事件以降から出没し始めた、不完全なシャドウです。","ENG":"Incomplete Shadows that appeared after the Replacer Incident.","TWN":"就是克隆集團事件後開始出現的半吊子暗影。"},"stage":{"bg":"COUNTERSIDE_NORMAL","bgm":"THEMA_DIVE_BOTTOM","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JOOSHIYOON_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L17_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_NULL_NULL","text":{"KOREA":"본체의 생사여부와 관계없이 나타나는 존재라고 하더군요.","JPN":"本体の生死と関係なく現れる存在らしいですね。","ENG":"They materialize regardless of their original's status: dead or alive.","TWN":"他們的出現和本體的生死無關。"},"stage":{"bg":"COUNTERSIDE_NORMAL","bgm":"THEMA_DIVE_BOTTOM","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JOOSHIYOON_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L18_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"그렇단 말이지?","JPN":"なるほどね。","ENG":"I see.","TWN":"是這樣喔？"},"stage":{"bg":"COUNTERSIDE_NORMAL","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JOOSHIYOON_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L20_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"난 준비됐어. 언제라도 신호를 줘, 선배.","JPN":"私はもう準備できてるよ。いつでも合図して、先輩。","ENG":"I'm ready. You just say when.","TWN":"前輩，我準備好了，就等你發號施令。"},"stage":{"bg":"COUNTERSIDE_NORMAL","bgm":"BATTLE_BOSS_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_NULL_NULL","text":{"KOREA":"괜찮으시겠어요? 도플갱어라곤 해도 원본을 꼭 빼 닮았는데요?","JPN":"いいんですか？　ドッペルゲンガーとはいえ、本体そっくりですよ？","ENG":"Are you sure? Doppelgangers or not, they look just like the originals.","TWN":"你OK嗎？雖然是二重身，但和主體應該很相似。"},"stage":{"bg":"COUNTERSIDE_NORMAL","bgm":"BATTLE_BOSS_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JOOSHIYOON_FENRIR_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_NULL_NULL","text":{"KOREA":"저 익숙한 얼굴이 결정적인 순간에 망설임을 가져올 지도 모릅니다.","JPN":"あの見慣れた顔のせいで、大事な瞬間に迷いが出るかもしれません。","ENG":"Their familiar faces can distract you at the most inopportune moment.","TWN":"在關鍵的時刻，那些熟悉的面孔可能會讓你下不了手。"},"stage":{"bg":"COUNTERSIDE_NORMAL","bgm":"BATTLE_BOSS_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JOOSHIYOON_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"걱정 마.","JPN":"心配しないで。","ENG":"Don't worry.","TWN":"放心吧！"},"stage":{"bg":"COUNTERSIDE_NORMAL","bgm":"BATTLE_BOSS_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L24_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"TV에서 말한대로라면, 저건 내가 알고 있는 진짜가 아니라는 거잖아?","JPN":"あのテレビの話しどおりなら、アレは私の知っている本物ではないってことでしょ？","ENG":"If what the TV said is true, they're not the real ones that I know, right?","TWN":"就像電視說的一樣，他們不是我認識的本尊，只是冒牌貨而已！"},"stage":{"bg":"COUNTERSIDE_NORMAL","bgm":"BATTLE_BOSS_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L25_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"더 이상 얄팍한 감정에 휘둘리는 실수 따윈 하지 않을 거니까.","JPN":"もう薄っぺらな感情に振り回されて失敗なんかしないから。","ENG":"I'm not going to let my emotions get the best of me.","TWN":"我不會再感情用事了！"},"stage":{"bg":"COUNTERSIDE_NORMAL","bgm":"BATTLE_BOSS_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L26_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_NULL_NULL","text":{"KOREA":"하하, 믿음직하네요.","JPN":"ハハハ、それは頼もしいですね。","ENG":"Hah hah. How reliable!","TWN":"哈哈，那麼可靠！"},"stage":{"bg":"COUNTERSIDE_NORMAL","bgm":"BATTLE_BOSS_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JOOSHIYOON_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L27_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_NULL_NULL","text":{"KOREA":"그럼 한 번 해보죠.","JPN":"では、やってみましょう。","ENG":"Alright, let's do this.","TWN":"那就放手一搏吧！"},"stage":{"bg":"COUNTERSIDE_NORMAL","bgm":"BATTLE_BOSS_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JOOSHIYOON_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L28_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_NULL_NULL","text":{"KOREA":"귀띔해줘서 고마워요, TV 씨.","JPN":"ヒント助かりましたよ、テレビさん。","ENG":"Thank you for the tip, Mr. TV.","TWN":"謝啦電視！謝謝你的提醒！"},"stage":{"bg":"COUNTERSIDE_NORMAL","bgm":"BATTLE_BOSS_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JOOSHIYOON_FENRIR_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}}]`);export{e as default};